INSERT INTO runpsy_articles (slug, title, description, date, author_slug, category_slug, tags, reading_time, seo_title, seo_description, status, intent, cta, safety_note, related_slugs, introduction, insight_impulse, sections, faq, quiz, sort_order) VALUES

-- Статья 11: Как говорить о чувствах
('kak-govorit-o-chuvstvakh',
 'Как говорить о чувствах (Без страха и обвинений)',
 'Говорить о чувствах — навык, который большинство никогда не изучало. Когда вы называете эмоцию вслух, активность миндалевидного тела снижается вдвое.',
 '2026-05-03',
 'runpsy-editorial-team',
 'relationships',
 '["чувства","я-сообщения","коммуникация","амигдала","уязвимость"]',
 '8 мин',
 'Как говорить о чувствах без страха и обвинений | RunPsy',
 'Как называть свои эмоции партнёру, не нападая. Я-сообщения, нейробиология уязвимости и практика честного диалога.',
 'published',
 'эмоциональный',
 'Признайтесь партнеру в одной позитивной или нейтральной эмоции без повода. Например: «Я сейчас чувствую такое спокойствие, когда мы просто сидим рядом».',
 'Если любая попытка сказать о своих чувствах вызывает у партнера жестокий газлайтинг («Ты неадекватна, тебе лечиться надо»), и вы начинаете сомневаться в своей вменяемости.',
 '["kak-prekratit-tsiklichnye-ssory","emotsionalnaya-zrelost-v-pare","kommunikatsiya-bez-passivnoy-agressii"]',
 'Говорить о чувствах — это навык, который большинство из нас никогда не изучало. В детстве многих учили скрывать свои эмоции, называя слезы слабостью, а злость — плохим характером. Из-за этого наша нервная система привыкла воспринимать уязвимость как прямую угрозу. Когда мы пытаемся сказать партнеру, что нам больно или одиноко, в мозге мгновенно активируется миндалевидное тело (амигдала). Она запускает реакцию «бей или беги», воспринимая разговор как выход на поле боя. Именно поэтому мы часто либо замолкаем, проглатывая обиду, либо взрываемся претензиями и криком. Мы не говорим о чувствах, мы нападаем или защищаемся. Префронтальная кора, отвечающая за логику и эмпатию, в этот момент просто отключается. Вы хотите сказать: «Мне страшно, что я тебе не нужен», но вместо этого произносите: «Ты вечно занят только собой».',
 '{"painPoint":"Вы хотите обсудить то, что вас задело, но вместо спокойного диалога скатываетесь в слезы или крик. Партнер раздражается и уходит, а вы остаетесь с разъедающим чувством вины.","essence":[{"title":"Суть за 30 секунд","text":"Говорить о чувствах — это не признак слабости, а инструмент регуляции нервной системы. Когда вы озвучиваете свои эмоции в виде фактов («я злюсь», «мне страшно»), вы снижаете уровень кортизола и снимаете напряжение в паре. Нападение и критика лишь блокируют эмпатию партнера. Честный диалог начинается с «Я-сообщений», которые приглашают к сотрудничеству, а не к войне."}],"microAction":"Прежде чем начать сложный разговор, напишите претензию на бумаге. Затем вычеркните слово «Ты» и все производные, переформулировав мысль через: «Я чувствую [эмоция], когда происходит [факт]».","checklist":["Говорю ли я о своих эмоциях, не обвиняя при этом личность партнера?","Делаю ли я паузу перед тем, как ответить на колкость?","Использую ли я обобщения «всегда» и «никогда» во время ссор?"],"dialogue":[{"instead":"Ты вечно пялишься в телефон, когда я с тобой разговариваю!","try":"Когда я говорю, а ты смотришь в экран, я чувствую себя неважной и злюсь. Мне нужно твое внимание на пять минут.","why":"Описывает факт и чувство без атаки на личность партнера."}],"twoSides":{"firstTitle":"Если назвать чувство","firstItems":["Партнер услышит уязвимость","Сработают зеркальные нейроны","Напряжение снизится"],"secondTitle":"Если нападать","secondItems":["Партнер уйдет в защиту","Эмпатия заблокирована","Конфликт эскалирует"],"bridge":"Названная эмоция — это не слабость, а ключ к контакту."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Говорить о чувствах — это не признак слабости, а инструмент регуляции нервной системы. Когда вы озвучиваете свои эмоции в виде фактов («я злюсь», «мне страшно»), вы снижаете уровень кортизола и снимаете напряжение в паре. Нападение и критика лишь блокируют эмпатию партнера. Честный диалог начинается с «Я-сообщений», которые приглашают к сотрудничеству, а не к войне."]},{"title":"Точка боли","paragraphs":["Вы хотите обсудить то, что вас задело, но вместо спокойного диалога скатываетесь в слезы или крик. Партнер раздражается, называет вас истеричкой или уходит в другую комнату, а вы остаетесь с разъедающим чувством вины и абсолютной непонятости."]},{"title":"Почему это происходит","paragraphs":["Амигдалярный захват (Amygdala Hijack) и дефицит эмоционального словаря (алекситимия). Мозг считывает уязвимость как угрозу выживанию, отключая логическую часть.","Вы не можете подобрать слова, потому что ваше тело физически готовится к отражению удара, конвертируя страх во внешнюю агрессию или оцепенение."]},{"title":"Плохие советы","paragraphs":["«Держи эмоции при себе, будь выше этого», «Выскажи ему всё, что накипело, пусть знает», «Намекни ему, если любит — сам догадается»."]},{"title":"Что помогает","paragraphs":["Использование строгого формата «Я-сообщений». Разделение самого факта события и вашей эмоциональной реакции на него. Смещение фокуса с обвинения партнера на описание своего физиологического состояния."]},{"title":"Микро-действие","paragraphs":["Прежде чем начать сложный разговор, напишите претензию на бумаге. Затем вычеркните из нее слово «Ты» и все производные, переформулировав мысль через: «Я чувствую [эмоция], когда происходит [факт]»."]},{"title":"Конструктор диалогов","paragraphs":["Вместо «Ты вечно пялишься в телефон, когда я с тобой разговариваю!» — «Когда я говорю, а ты смотришь в экран, я чувствую себя неважной и злюсь. Мне нужно твое внимание на пять минут»."]},{"title":"Сценарии 50/50","paragraphs":["Либо партнер услышит вашу уязвимость и отложит телефон (сработают зеркальные нейроны эмпатии).","Либо он начнет защищаться — но вы сохраните эмоциональный контроль, так как не инициировали открытую атаку."]},{"title":"Чек-лист","paragraphs":["[ ] Говорю ли я о своих эмоциях, не обвиняя при этом личность партнера?","[ ] Делаю ли я паузу перед тем, как ответить на колкость?","[ ] Использую ли я обобщения «всегда» и «никогда» во время ссор?"]},{"title":"Когда нужен специалист","paragraphs":["Если любая попытка сказать о своих чувствах вызывает у партнера жестокий газлайтинг («Ты неадекватна, тебе лечиться надо»), и вы начинаете сомневаться в своей вменяемости."]},{"title":"Итог «что сделать сегодня»","paragraphs":["Признайтесь партнеру в одной позитивной или нейтральной эмоции без повода. Например: «Я сейчас чувствую такое спокойствие, когда мы просто сидим рядом»."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Как вы обычно выражаете недовольство?","questions":[{"question":"Когда вас что-то задело, что вы делаете первым?","options":["Говорю о своём чувстве спокойно","Начинаю упрекать партнёра","Замолкаю и дуюсь"]},{"question":"Вы используете фразы «ты всегда» или «ты никогда»?","options":["Редко или никогда","Иногда","Часто, когда злюсь"]}],"resultNote":"Ваш стиль выражения эмоций напрямую определяет качество диалога в паре."}',
 20),

-- Статья 14: Как прекратить цикличные ссоры
('kak-prekratit-tsiklichnye-ssory',
 'Как прекратить цикличные ссоры',
 'Цикличные ссоры — это заезженная нейронная программа. Вы спорите не о проблеме, а о скрытых потребностях в уважении и безопасности.',
 '2026-05-03',
 'runpsy-editorial-team',
 'relationships',
 '["ссоры","конфликт","паттерн","нейронные пути","кортизол"]',
 '8 мин',
 'Как прекратить цикличные ссоры: разрыв нейронного паттерна | RunPsy',
 'Почему пары ссорятся по одному и тому же кругу. Как разорвать автоматический паттерн конфликта и вернуть безопасность.',
 'published',
 'эмоциональный',
 'Договоритесь с партнером о «стоп-слове» для ссор. Это должно быть нелепое слово (например, «брокколи»), которое любой из вас может сказать, чтобы немедленно поставить конфликт на паузу.',
 'Если цикличные ссоры регулярно переходят в крушение мебели, оскорбления, унижающие человеческое достоинство, или физическое насилие.',
 '["kak-govorit-o-chuvstvakh","emotsionalnaya-zrelost-v-pare","kommunikatsiya-bez-passivnoy-agressii"]',
 'Каждая пара знает этот изматывающий сценарий. Вы снова и снова ссоритесь из-за одних и тех же вещей: невымытой посуды, времени возвращения домой или тона голоса. Декорации могут меняться, но диалог всегда идентичен. Вы точно знаете, что партнер ответит на вашу фразу, и знаете, как на это отреагируете вы. Эта предсказуемость сводит с ума, но вырваться из петли кажется невозможным. Нейробиология объясняет это явление формированием жестких нейронных путей. Ваша нервная система автоматизировала реакцию на конкретный триггер, чтобы сэкономить энергию. Когда звучит знакомая претензия, мозг не анализирует ситуацию заново. Он просто запускает старую программу защиты, сохраненную в лимбической системе.',
 '{"painPoint":"Вы открываете рот, чтобы сделать мелкое замечание, и через три минуты обнаруживаете себя в эпицентре скандала, где вам припоминают ошибки пятилетней давности. Вы истощены и чувствуете безнадежность.","essence":[{"title":"Суть за 30 секунд","text":"Цикличные ссоры — это заезженная нейронная программа, в которой вы спорите не о проблеме, а о скрытых потребностях в уважении и безопасности. Логика здесь не работает. Чтобы остановить петлю, нужно сломать алгоритм: отказаться от заученной реплики и переключить мозг партнера из защиты в ступор через неожиданно мягкую реакцию."}],"microAction":"Как только вы понимаете, что ссора пошла по привычному кругу, физически измените положение тела. Если вы стояли — сядьте на пол. Если кричали — резко перейдите на шепот.","checklist":["Спорю ли я сейчас о фактах, или пытаюсь доказать, что меня не ценят?","Могу ли я отследить момент, когда у меня учащается пульс перед началом скандала?","Готов ли я первым остановить ссору, даже если считаю себя правым?"],"dialogue":[{"instead":"Ты опять меня не слушаешь, как всегда!","try":"Мы снова начали ругаться по тому же кругу. Я не хочу с тобой воевать. Давай прервемся на 20 минут и выпьем воды.","why":"Называет паттерн вслух и предлагает выход без обвинений."}],"twoSides":{"firstTitle":"Если взять паузу","firstItems":["Кортизол снижается","Появляется возможность услышать","Ссора не раскручивается дальше"],"secondTitle":"Если продолжать по скрипту","secondItems":["Нейронный путь укрепляется","Конфликт эскалирует","Старые обиды всплывают снова"],"bridge":"Кто первым выходит из сценария — тот выигрывает."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Цикличные ссоры — это заезженная нейронная программа, в которой вы спорите не о проблеме, а о скрытых потребностях в уважении и безопасности. Логика здесь не работает. Чтобы остановить петлю, нужно сломать алгоритм: отказаться от заученной реплики и переключить мозг партнера из защиты в ступор через неожиданно мягкую реакцию."]},{"title":"Точка боли","paragraphs":["Вы открываете рот, чтобы сделать мелкое замечание, и через три минуты обнаруживаете себя в эпицентре скандала, где вам припоминают ошибки пятилетней давности. Вы истощены и чувствуете безнадежность."]},{"title":"Почему это происходит","paragraphs":["Жесткие нейронные пути и проекция страхов. Лимбическая система мгновенно распознает триггер (интонацию, взгляд) и включает режим защиты.","В этот момент префронтальная кора (центр логики) обесточена, и вы физиологически не способны услышать разумные аргументы друг друга."]},{"title":"Плохие советы","paragraphs":["«Никогда не ложитесь спать в ссоре» (сон снижает кортизол, иногда лучше лечь спать), «Заставь его признать свою неправоту», «Игнорируй его, пока не остынет»."]},{"title":"Что помогает","paragraphs":["Техника прерывания шаблона (Pattern Interrupt). Физическое или вербальное действие, которое выбивается из привычного сценария ссоры. Возвращение фокуса с предмета спора на эмоцию, которая стоит за ним."]},{"title":"Микро-действие","paragraphs":["Как только вы понимаете, что ссора пошла по привычному кругу, физически измените положение тела. Если вы стояли — сядьте на пол. Если кричали — резко перейдите на шепот. Сбой шаблона заставит мозг партнера притормозить."]},{"title":"Конструктор диалогов","paragraphs":["Вместо «Ты опять меня не слушаешь, как всегда!» — «Мы снова начали ругаться по тому же кругу. Я не хочу с тобой воевать. Давай прервемся на 20 минут и выпьем воды»."]},{"title":"Сценарии 50/50","paragraphs":["Либо партнер воспользуется паузой, чтобы выдохнуть и снизить градус.","Либо продолжит нападать по инерции, и тогда вам придется физически выйти из комнаты, спасая свои границы."]},{"title":"Чек-лист","paragraphs":["[ ] Спорю ли я сейчас о фактах, или пытаюсь доказать, что меня не ценят?","[ ] Могу ли я отследить момент, когда у меня учащается пульс перед началом скандала?","[ ] Готов ли я первым остановить ссору, даже если считаю себя правым?"]},{"title":"Когда нужен специалист","paragraphs":["Если цикличные ссоры регулярно переходят в крушение мебели, оскорбления, унижающие человеческое достоинство, или физическое насилие."]},{"title":"Итог «что сделать сегодня»","paragraphs":["Договоритесь с партнером о «стоп-слове» для ссор. Это должно быть нелепое слово (например, «брокколи»), которое любой из вас может сказать, чтобы немедленно поставить конфликт на паузу."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Насколько вы вовлечены в циклический конфликт?","questions":[{"question":"Вы ссоритесь об одном и том же уже больше трёх раз?","options":["Нет, каждый раз что-то новое","Да, есть 1-2 повторяющихся темы","Да, почти каждая ссора — одна и та же"]},{"question":"Что происходит после ссоры?","options":["Миримся, тема закрыта","Замолкаем, но напряжение остаётся","Ничего не меняется, ждём следующего раза"]}],"resultNote":"Повторяющийся конфликт — это сигнал о непрожитой потребности, а не о конкретной проблеме."}',
 21),

-- Статья 24: Эмоциональная зрелость в паре
('emotsionalnaya-zrelost-v-pare',
 'Эмоциональная зрелость в паре',
 'Эмоциональная зрелость — это способность выдерживать внутренний дискомфорт, не превращая партнера в мишень или спасателя.',
 '2026-05-03',
 'runpsy-editorial-team',
 'relationships',
 '["зрелость","ответственность","регрессия","эмоциональный интеллект","автономия"]',
 '9 мин',
 'Эмоциональная зрелость в паре: личная ответственность и зрелая любовь | RunPsy',
 'Что такое эмоциональная зрелость и почему возраст её не гарантирует. Как перестать требовать от партнёра родительской любви.',
 'published',
 'эмоциональный',
 'Сформулируйте одну просьбу к партнеру предельно прямо и словами, без намеков и тяжелых вздохов. «Я устал, сделай, пожалуйста, чай».',
 'Если любой отказ партнера вызывает у вас самоповреждающее поведение, истерики с битьем посуды или угрозы разрушить свою жизнь.',
 '["kak-govorit-o-chuvstvakh","kommunikatsiya-bez-passivnoy-agressii","lichnye-granicy-v-pare"]',
 'Мы привыкли считать, что возраст автоматически приносит с собой взрослость. Однако эмоциональная зрелость не измеряется цифрами в паспорте, наличием ипотеки или руководящей должностью. В моменты сильного стресса или конфликта большинство из нас мгновенно откатывается к базовым детским реакциям. Мы обижаемся, замолкаем, хлопаем дверью или требуем, чтобы партнер догадался о наших желаниях. Это происходит потому, что лимбическая система перехватывает управление у префронтальной коры. Эмоциональная незрелость — это неспособность выдерживать напряжение без попыток немедленно сбросить его на другого человека. Незрелый партнер использует отношения как контейнер для своей тревоги, превращая второго человека в родителя.',
 '{"painPoint":"Вы молчите в надежде, что партнер поймет вашу обиду по выражению лица. А когда он не догадывается, вы взрываетесь обвинениями: «Тебе вообще наплевать на меня!». Вы чувствуете себя брошенным ребенком.","essence":[{"title":"Суть за 30 секунд","text":"Эмоциональная зрелость — это способность выдерживать внутренний дискомфорт, не превращая партнера в мишень или спасателя. Это навык отделять свои старые травмы от текущей ситуации. Зрелая любовь не требует полного слияния и идеальности; она строится на честности, личной ответственности и умении восстанавливать связь после конфликта."}],"microAction":"Заведите правило 10 секунд. Прежде чем отреагировать на раздражающие слова партнера, медленно сосчитайте до десяти про себя.","checklist":["Жду ли я, что партнер догадается о моих желаниях сам?","Обвиняю ли я партнера в своих неудачах или плохом настроении?","Умею ли я извиняться первым, если понял свою ошибку?"],"dialogue":[{"instead":"Ты заставляешь меня чувствовать себя ничтожеством!","try":"Когда ты критикуешь мои решения при друзьях, я чувствую унижение. Пожалуйста, давай обсуждать это наедине.","why":"Переводит обвинение в конкретную просьбу о поведении."}],"twoSides":{"firstTitle":"Если взять ответственность","firstItems":["Отношения становятся безопасными","Партнер расслабляется рядом","Глубина контакта растёт"],"secondTitle":"Если требовать родительской любви","secondItems":["Партнер истощается","Либидо и уважение угасают","Отношения превращаются в терапию"],"bridge":"Зрелость — это свобода от бесконечных детских драм."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Эмоциональная зрелость — это способность выдерживать внутренний дискомфорт, не превращая партнера в мишень или спасателя. Это навык отделять свои старые травмы от текущей ситуации. Зрелая любовь не требует полного слияния и идеальности; она строится на честности, личной ответственности и умении восстанавливать связь после конфликта."]},{"title":"Точка боли","paragraphs":["Вы молчите в надежде, что партнер поймет вашу обиду по выражению лица. А когда он не догадывается, вы взрываетесь обвинениями: «Тебе вообще наплевать на меня!». Вы чувствуете себя брошенным ребенком."]},{"title":"Почему это происходит","paragraphs":["Эмоциональный регресс и отсутствие сепарации. В состоянии стресса психика откатывается к механизмам выживания раннего возраста.","Если в детстве истерика или бойкот помогали привлечь внимание, взрослый мозг будет воспроизводить этот паттерн, требуя от партнера родительской опеки."]},{"title":"Плохие советы","paragraphs":["«Партнеры должны понимать друг друга без слов», «Просто найди человека, который будет принимать твои истерики», «Настоящая любовь не требует работы над собой»."]},{"title":"Что помогает","paragraphs":["Принятие на себя 100% ответственности за свое настроение. Понимание того, что никто не обязан читать ваши мысли. Отказ от проекции фигуры отца/матери на своего супруга."]},{"title":"Микро-действие","paragraphs":["Заведите правило 10 секунд. Прежде чем отреагировать на раздражающие слова партнера, медленно сосчитайте до десяти про себя. Это время необходимо префронтальной коре, чтобы заблокировать импульс."]},{"title":"Конструктор диалогов","paragraphs":["Вместо «Ты заставляешь меня чувствовать себя ничтожеством!» — «Когда ты критикуешь мои решения при друзьях, я чувствую унижение. Пожалуйста, давай обсуждать это наедине»."]},{"title":"Сценарии 50/50","paragraphs":["Либо вы берете на себя ответственность, и ваши отношения становятся глубокими и безопасными.","Либо вы продолжаете требовать безусловной родительской любви от партнера, медленно убивая его либидо и уважение."]},{"title":"Чек-лист","paragraphs":["[ ] Жду ли я, что партнер догадается о моих желаниях сам?","[ ] Обвиняю ли я партнера в своих неудачах или плохом настроении?","[ ] Умею ли я извиняться первым, если понял свою ошибку?"]},{"title":"Когда нужен специалист","paragraphs":["Если любой отказ партнера вызывает у вас самоповреждающее поведение, истерики с битьем посуды или угрозы разрушить свою жизнь."]},{"title":"Итог «что сделать сегодня»","paragraphs":["Сформулируйте одну просьбу к партнеру предельно прямо и словами, без намеков и тяжелых вздохов. «Я устал, сделай, пожалуйста, чай»."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Насколько вы emotionally mature в паре?","questions":[{"question":"Когда партнёр вас расстраивает, вы...","options":["Говорю об этом прямо","Жду что он сам поймёт","Обвиняю его в своих переживаниях"]},{"question":"Как часто вы берёте ответственность за своё настроение?","options":["Всегда — это мои эмоции","Иногда, зависит от ситуации","Редко — обычно виноват партнёр"]}],"resultNote":"Уровень личной ответственности — фундамент зрелых отношений."}',
 22),

-- Статья 25: Коммуникация без пассивной агрессии
('kommunikatsiya-bez-passivnoy-agressii',
 'Коммуникация без пассивной агрессии',
 'Пассивная агрессия — это яд, который убивает отношения медленно и незаметно. Она рождается из страха перед прямым конфликтом.',
 '2026-05-03',
 'runpsy-editorial-team',
 'couple-boundaries',
 '["пассивная агрессия","сарказм","манипуляция","сайлент-тритмент","коммуникация"]',
 '8 мин',
 'Коммуникация без пассивной агрессии: как говорить прямо | RunPsy',
 'Как перестать использовать сарказм, молчание и саботаж. Путь от скрытого контроля к прямой и честной коммуникации.',
 'published',
 'эмоциональный',
 'Отследите один момент, когда захочется съязвить или тяжело вздохнуть. Остановите себя и промолчите. Просто зафиксируйте этот паттерн.',
 'Если пассивная агрессия партнера переходит в газлайтинг («тебе показалось», «у тебя паранойя»), и вы начинаете сомневаться в своей способности адекватно воспринимать реальность.',
 '["kak-govorit-o-chuvstvakh","emotsionalnaya-zrelost-v-pare","kak-prekratit-tsiklichnye-ssory"]',
 'Пассивная агрессия — это яд, который убивает отношения медленно и совершенно незаметно. Громкий скандал можно обсудить и забыть, но тяжелые вздохи, закатывание глаз и холодное «всё нормально» отравляют атмосферу на недели. Люди используют пассивную агрессию не из-за жестокости, а из-за парализующего страха перед прямым конфликтом. В детстве многим из нас запрещали открыто выражать злость, наказывая за любое проявление недовольства. Мозг усвоил, что прямая конфронтация угрожает базовой безопасности и может привести к отвержению. Но невысказанная эмоция никуда не исчезает, она лишь меняет форму и ищет обходные пути.',
 '{"painPoint":"Партнер спрашивает, что случилось, а вы с ледяным лицом отвечаете: «Ничего, всё просто отлично», при этом громко хлопая дверцами шкафов. Вы ждете, что он начнет извиняться и вымаливать прощение.","essence":[{"title":"Суть за 30 секунд","text":"Пассивная агрессия — это форма скрытого контроля и наказания, рожденная из страха перед открытым конфликтом. Вы боитесь сказать прямо, поэтому используете сарказм, игнорирование или саботаж, чтобы партнер «сам всё понял». Это разрушает доверие. Единственный выход — разрешить себе злиться в открытую и говорить о недовольстве фактами, а не намеками."}],"microAction":"Запретите себе фразу «всё нормально», когда это не так. Если вы не готовы говорить прямо сейчас, скажите: «Я сейчас злюсь и не готова это обсуждать. Вернемся к разговору через час».","checklist":["Использую ли я сарказм, чтобы замаскировать обиду?","Наказываю ли я партнера молчанием (сайлент-тритмент)?","Могу ли я спокойно сказать вслух: «Я на тебя сейчас злюсь»?"],"dialogue":[{"instead":"О, конечно, иди отдыхай, я сама всё уберу, мне же не привыкать.","try":"Я устала и злюсь, что уборка осталась только на мне. Мне нужна твоя помощь с кухней прямо сейчас.","why":"Называет чувство и содержит конкретную просьбу без скрытого укора."}],"twoSides":{"firstTitle":"Если говорить прямо","firstItems":["Напряжение снимается","Партнер понимает что нужно","Доверие растёт"],"secondTitle":"Если продолжать намекать","secondItems":["Партнер дезориентирован","Накапливается скрытая обида","Атмосфера постепенно отравляется"],"bridge":"Прямолинейность — это уважение, а не агрессия."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Пассивная агрессия — это форма скрытого контроля и наказания, рожденная из страха перед открытым конфликтом. Вы боитесь сказать прямо, поэтому используете сарказм, игнорирование или саботаж, чтобы партнер «сам всё понял». Это разрушает доверие. Единственный выход — разрешить себе злиться в открытую и говорить о недовольстве фактами, а не намеками."]},{"title":"Точка боли","paragraphs":["Партнер спрашивает, что случилось, а вы с ледяным лицом отвечаете: «Ничего, всё просто отлично», при этом громко хлопая дверцами шкафов. Вы ждете, что он начнет извиняться и вымаливать прощение."]},{"title":"Почему это происходит","paragraphs":["Запрет на проявление агрессии и избегание уязвимости. Нервная система воспринимает прямой конфликт как угрозу выживанию (страх быть отвергнутым).","Психика находит «безопасный» способ сбросить кортизоловое напряжение через микро-саботаж, не беря на себя ответственность за ссору."]},{"title":"Плохие советы","paragraphs":["«Отвечай сарказмом на сарказм», «Просто игнорируй его вздохи, сам успокоится», «Намекни ему потолще, чтобы дошло»."]},{"title":"Что помогает","paragraphs":["Переход к прямолинейной, безоценочной коммуникации. Снятие с себя ответственности за то, как партнер воспримет вашу правду. Понимание того, что конфликт — это нормальная точка роста, а не конец света."]},{"title":"Микро-действие","paragraphs":["Запретите себе фразу «всё нормально», когда это не так. Если вы не готовы говорить прямо сейчас, скажите: «Я сейчас злюсь и не готова это обсуждать. Вернемся к разговору через час»."]},{"title":"Конструктор диалогов","paragraphs":["Вместо «О, конечно, иди отдыхай, я сама всё уберу, мне же не привыкать» — «Я устала и злюсь, что уборка осталась только на мне. Мне нужна твоя помощь с кухней прямо сейчас»."]},{"title":"Сценарии 50/50","paragraphs":["Либо прямой разговор приведет к конструктивному решению и снятию напряжения.","Либо партнер не выдержит вашей прямоты — но вы, по крайней мере, перестанете тратить энергию на эмоциональные игры."]},{"title":"Чек-лист","paragraphs":["[ ] Использую ли я сарказм, чтобы замаскировать обиду?","[ ] Наказываю ли я партнера молчанием (сайлент-тритмент)?","[ ] Могу ли я спокойно сказать вслух: «Я на тебя сейчас злюсь»?"]},{"title":"Когда нужен специалист","paragraphs":["Если пассивная агрессия партнера переходит в газлайтинг («тебе показалось», «у тебя паранойя»), и вы начинаете сомневаться в своей способности адекватно воспринимать реальность."]},{"title":"Итог «что сделать сегодня»","paragraphs":["Отследите один момент, когда захочется съязвить или тяжело вздохнуть. Остановите себя и промолчите. Просто зафиксируйте этот паттерн."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Как вы выражаете скрытое недовольство?","questions":[{"question":"Как часто вы говорите «всё нормально», когда это не так?","options":["Редко — стараюсь говорить прямо","Иногда, когда не готова к разговору","Часто — проще промолчать"]},{"question":"Вы используете молчание как наказание?","options":["Нет, это не мой метод","Иногда, чтобы дать сигнал","Да, это работает лучше слов"]}],"resultNote":"Осознание своих пассивно-агрессивных паттернов — первый шаг к честной коммуникации."}',
 23),

-- Статья 26: Финансовые конфликты в паре
('finansovye-konflikty-v-pare',
 'Финансовые конфликты в паре',
 'Финансовые конфликты — это конфликты вокруг психологической безопасности и власти. Деньги — это никогда не про деньги.',
 '2026-05-03',
 'runpsy-editorial-team',
 'relationships',
 '["деньги","бюджет","финансы","безопасность","доверие"]',
 '9 мин',
 'Финансовые конфликты в паре: психология денег в отношениях | RunPsy',
 'Почему пары ссорятся из-за денег. Психология финансовых конфликтов, финансовая измена и как выстроить бюджет доверия.',
 'published',
 'кризисный',
 'Признайтесь себе, какую эмоцию вы чаще всего «покупаете» за деньги (статус, спокойствие, радость). Запишите это в заметки на телефоне.',
 'Если в семье скрываются крупные кредиты, присутствует игровая зависимость (лудомания) или партнер использует деньги для шантажа и изоляции.',
 '["emotsionalnaya-zrelost-v-pare","lichnye-granicy-v-pare","toksichnye-otnosheniya-priznaki"]',
 'Деньги в отношениях — это почти никогда не про сами купюры или цифры на банковском счете. Финансовые конфликты всегда скрывают под собой борьбу за власть, безопасность или свободу. Для одного человека накопления означают спокойствие и защиту от непредсказуемого мира. Для другого импульсивные траты — это легальный способ получить дофамин и почувствовать себя живым. Когда эти две нейробиологические стратегии сталкиваются в одной семье, начинается война. Мозг воспринимает угрозу финансам как прямую угрозу биологическому выживанию. Именно поэтому споры о бюджете мгновенно переходят в агрессию и активируют амигдалу.',
 '{"painPoint":"Вы находите чек на дорогую покупку, о которой партнер умолчал. У вас перехватывает дыхание от паники и злости: вам кажется, что вы экономите на всем, пока он разрушает ваше общее будущее.","essence":[{"title":"Суть за 30 секунд","text":"Финансовые конфликты — это конфликты вокруг психологической безопасности и власти. Мозг реагирует на нехватку или потерю денег как на физическую угрозу жизни. Чтобы перестать ругаться, нужно понять: деньги для вашего партнера — это инструмент контроля, свободы или статуса? Решение лежит в создании системы, где у каждого есть «неприкосновенная» зона для удовлетворения своих нейробиологических потребностей."}],"microAction":"Сядьте рядом и задайте друг другу один вопрос: «Какое твое самое раннее воспоминание о деньгах в детстве?». Выслушайте ответ без комментариев.","checklist":["Скрываю ли я свои покупки от партнера?","Отношусь ли я к партнеру как к ребенку, который не умеет распоряжаться ресурсами?","Обсуждали ли мы когда-нибудь наши долгосрочные страхи, связанные с бедностью?"],"dialogue":[{"instead":"Ты опять спустил деньги на ерунду!","try":"Когда ты делаешь крупные покупки без обсуждения, мне становится страшно за нашу безопасность. Давай договоримся о лимите, выше которого мы советуемся.","why":"Называет страх, а не обвиняет, и содержит конкретное предложение."}],"twoSides":{"firstTitle":"Если выстроить систему доверия","firstItems":["Оба чувствуют защищённость","Скрытых трат больше нет","Финансы становятся зоной сотрудничества"],"secondTitle":"Если продолжать контролировать","secondItems":["Нарастает ресентимент","Скрытые траты учащаются","Финансовый абьюз углубляется"],"bridge":"Прозрачность в финансах — это высшая форма уважения к чужому чувству безопасности."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Финансовые конфликты — это конфликты вокруг психологической безопасности и власти. Мозг реагирует на нехватку или потерю денег как на физическую угрозу жизни. Чтобы перестать ругаться, нужно понять: деньги для вашего партнера — это инструмент контроля, свободы или статуса? Решение лежит в создании системы, где у каждого есть «неприкосновенная» зона для удовлетворения своих нейробиологических потребностей."]},{"title":"Точка боли","paragraphs":["Вы находите чек на дорогую покупку, о которой партнер умолчал. У вас перехватывает дыхание от паники и злости: вам кажется, что вы экономите на всем, пока он разрушает ваше общее будущее."]},{"title":"Почему это происходит","paragraphs":["Угроза выживанию и финансовые травмы детства. Снижение ресурса активирует стрессовый ответ (кортизол).","Трансгенерационные сценарии заставляют одного партнера патологически копить (реакция страха), а другого — импульсивно спускать (дофаминовый сброс напряжения)."]},{"title":"Плохие советы","paragraphs":["«Забирай у него всю зарплату и выдавай на проезд», «У каждого должны быть только свои деньги, никакого общака», «Прячь от него заначку на черный день»."]},{"title":"Что помогает","paragraphs":["Переход от обвинений в безответственности к исследованию страхов. Создание смешанного бюджета: общий счет на базовые нужды и два личных счета, траты с которых не обсуждаются и не критикуются."]},{"title":"Микро-действие","paragraphs":["Сядьте рядом и задайте друг другу один вопрос: «Какое твое самое раннее воспоминание о деньгах в детстве?». Выслушайте ответ без комментариев."]},{"title":"Конструктор диалогов","paragraphs":["Вместо «Ты опять спустил деньги на ерунду!» — «Когда ты делаешь крупные покупки без обсуждения, мне становится страшно за нашу безопасность. Давай договоримся о лимите, выше которого мы советуемся»."]},{"title":"Сценарии 50/50","paragraphs":["Либо выстраивается прозрачная система доверия, где оба партнера чувствуют себя защищенными.","Либо вскрывается финансовый абьюз (один полностью контролирует другого), что требует кардинального пересмотра отношений."]},{"title":"Чек-лист","paragraphs":["[ ] Скрываю ли я свои покупки от партнера?","[ ] Отношусь ли я к партнеру как к ребенку, который не умеет распоряжаться ресурсами?","[ ] Обсуждали ли мы когда-нибудь наши долгосрочные страхи, связанные с бедностью?"]},{"title":"Когда нужен специалист","paragraphs":["Если в семье скрываются крупные кредиты, присутствует игровая зависимость (лудомания) или партнер использует деньги для шантажа и изоляции."]},{"title":"Итог «что сделать сегодня»","paragraphs":["Признайтесь себе, какую эмоцию вы чаще всего «покупаете» за деньги (статус, спокойствие, радость). Запишите это в заметки на телефоне."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Какова ваша финансовая стратегия в паре?","questions":[{"question":"Вы скрываете некоторые покупки от партнёра?","options":["Нет, у нас полная прозрачность","Иногда мелкие вещи","Да, регулярно"]},{"question":"Что для вас значат деньги прежде всего?","options":["Безопасность и стабильность","Свобода и удовольствие","Статус и уважение"]}],"resultNote":"Понимание вашего финансового архетипа — первый шаг к миру в паре."}',
